   edge2[0]=vert2[0]-vert0[0]; edge2[1]=vert2[1]-vert0[1]; edge2[2]=vert2[2]-vert0[2];;


   pvec[0]=dir[1]*edge2[2]-dir[2]*edge2[1]; pvec[1]=dir[2]*edge2[0]-dir[0]*edge2[2]; pvec[2]=dir[0]*edge2[1]-dir[1]*edge2[0];;


